using System.Text.RegularExpressions;
using QuickCode.Demo.Infrastructure.Web.Extensions;

namespace QuickCode.Demo.Infrastructure.Web.Helpers;

public static class GatewayServiceTokenModuleNameResolver
{
    public static string Resolve(IConfiguration configuration)
    {
        var moduleName = configuration["AppSettings:ModuleName"];
        if (!string.IsNullOrWhiteSpace(moduleName))
        {
            return moduleName;
        }

        var apiName = configuration["Logging:ApiName"];
        if (!string.IsNullOrWhiteSpace(apiName))
        {
            var match = Regex.Match(apiName, @"-([a-z0-9-]+)-api$", RegexOptions.IgnoreCase);
            if (match.Success)
            {
                var segment = match.Groups[1].Value;
                if (segment.Contains('-'))
                {
                    return segment.KebabCaseToPascal("");
                }

                if (segment.EndsWith("module", StringComparison.OrdinalIgnoreCase))
                {
                    var prefix = segment[..^"module".Length];
                    if (!string.IsNullOrEmpty(prefix))
                    {
                        return prefix.FirstCharToUpper() + "Module";
                    }
                }

                return segment.GetPascalCase();
            }
        }

        throw new InvalidOperationException(
            "AppSettings:ModuleName is required for gateway service token validation. " +
            "Set AppSettings:ModuleName or Logging:ApiName ending with '-{module}-api'.");
    }
}
